/**
 * Lake Group  offline knowledge assistant.
 *
 * Progressive-enhancement replacement for the legacy canned-reply chat in
 * assets/site.js. On load it takes over the existing `#chat-widget` mount
 * (creating one if the page has none), swaps in the assistant UI and sets
 * `window.__LAKE_ASSISTANT_ACTIVE__` so site.js's initChat() bails out.
 *
 * Retrieval: FlexSearch (assets/vendor/flexsearch/, Apache-2.0, vendored 
 * no CDN) over the build-time knowledge base in assets/assistant-kb.js
 * (generated by scripts/build_assistant_kb.js: curated verified facts +
 * per-page content chunks in en/fr/sw/hi/ar). Answers are verbatim retrieved
 * passages with light templating and a "Read more →" source link  the
 * assistant never generates text.
 *
 * Persistence: IndexedDB (db `lake-assistant`, store `messages`), feature-
 * detected with an in-memory fallback.
 *
 * i18n: all UI strings use assistant.* keys through window.LakeI18n; the
 * `lake-i18n-applied` event re-renders language-dependent parts live and
 * queries are answered from the current language's index.
 */
(function () {
  'use strict';

  // Read by the guard in site.js initChat(): the legacy chat must not bind.
  window.__LAKE_ASSISTANT_ACTIVE__ = true;

  var HISTORY_LIMIT = 100;
  var TYPING_DELAY = 260;

  /* ------------------------------------------------------------------ */
  /* i18n                                                                */
  /* ------------------------------------------------------------------ */
  // English fallbacks: used on pages without the i18n stack (404/offline)
  // or before dictionaries load. Keys mirror assistant.* in i18n-content.
  var FALLBACK = {
    'assistant.title': 'Lake Group Assistant',
    'assistant.placeholder': 'Ask about our services, countries\u2026',
    'assistant.send': 'Send',
    'assistant.open': 'Open the Lake Group assistant',
    'assistant.close': 'Close assistant',
    'assistant.clear': 'Clear conversation',
    'assistant.cleared': 'Conversation cleared. How can I help?',
    'assistant.greeting':
      "Hello! I'm the Lake Group assistant. Ask me about our services, countries, companies or how to get in touch.",
    'assistant.thanks': "You're welcome! Anything else you'd like to know?",
    'assistant.found': "Here's what I found:",
    'assistant.readmore': 'Read more \u2192',
    'assistant.nomatch':
      "I couldn't find that \u2014 try asking about our services, countries, or contacts, or visit the Contact page.",
  };

  function t(key) {
    if (window.LakeI18n) {
      var val = window.LakeI18n.t(key);
      if (val !== null && val !== undefined && val !== key) return val;
    }
    return FALLBACK[key] || key;
  }

  function lang() {
    var l = window.LakeI18n && window.LakeI18n.current;
    if (l === 'fr' || l === 'sw' || l === 'hi' || l === 'ar') return l;
    return 'en';
  }

  /* ------------------------------------------------------------------ */
  /* Persistence  IndexedDB with in-memory fallback                     */
  /* ------------------------------------------------------------------ */
  var storage = (function () {
    var memory = [];
    var dbPromise = null;

    function open() {
      if (dbPromise) return dbPromise;
      dbPromise = new Promise(function (resolve) {
        if (!('indexedDB' in window)) return resolve(null);
        try {
          var req = indexedDB.open('lake-assistant', 1);
          req.onupgradeneeded = function () {
            var db = req.result;
            if (!db.objectStoreNames.contains('messages')) {
              db.createObjectStore('messages', {
                keyPath: 'id',
                autoIncrement: true,
              });
            }
          };
          req.onsuccess = function () { resolve(req.result); };
          req.onerror = function () { resolve(null); };
          req.onblocked = function () { resolve(null); };
        } catch (e) {
          resolve(null);
        }
      });
      return dbPromise;
    }

    return {
      load: function () {
        return open().then(function (db) {
          if (!db) return memory.slice();
          return new Promise(function (resolve) {
            try {
              var out = [];
              var tx = db.transaction('messages', 'readonly');
              tx.objectStore('messages').openCursor().onsuccess = function (e) {
                var cur = e.target.result;
                if (cur) { out.push(cur.value); cur.continue(); }
              };
              tx.oncomplete = function () { resolve(out.slice(-HISTORY_LIMIT)); };
              tx.onerror = function () { resolve([]); };
            } catch (e) { resolve([]); }
          });
        });
      },
      add: function (msg) {
        return open().then(function (db) {
          if (!db) { memory.push(msg); return; }
          try {
            db.transaction('messages', 'readwrite')
              .objectStore('messages')
              .add(msg);
          } catch (e) { memory.push(msg); }
        });
      },
      clear: function () {
        memory = [];
        return open().then(function (db) {
          if (!db) return;
          return new Promise(function (resolve) {
            try {
              var tx = db.transaction('messages', 'readwrite');
              tx.objectStore('messages').clear();
              tx.oncomplete = resolve;
              tx.onerror = resolve;
            } catch (e) { resolve(); }
          });
        });
      },
    };
  })();

  /* ------------------------------------------------------------------ */
  /* Retrieval  FlexSearch over the build-time KB                       */
  /* ------------------------------------------------------------------ */
  var indexes = {}; // lang -> { idx, docs }

  function getIndex(l) {
    if (indexes[l]) return indexes[l];
    var kb = window.__LAKE_ASSISTANT_KB__;
    if (!kb || !kb.langs || !kb.langs[l] || !window.FlexSearch) return null;
    var docs = kb.langs[l].docs;
    var idx = new FlexSearch.Index({
      tokenize: 'forward',
      charset: 'latin:simple',
    });
    for (var i = 0; i < docs.length; i++) {
      var d = docs[i];
      // Titles + hand-picked keywords weigh in alongside the passage text.
      idx.add(i, d.t + ' ' + (d.k || '') + ' ' + d.s);
    }
    indexes[l] = { idx: idx, docs: docs };
    return indexes[l];
  }

  function factById(l, id) {
    var entry = getIndex(l);
    if (!entry) return null;
    for (var i = 0; i < entry.docs.length; i++) {
      if (entry.docs[i].id === 'fact:' + id) return entry.docs[i];
    }
    return null;
  }

  // Interrogatives/fillers that only add noise: with forward tokenization a
  // query word like "una" (sw) or "do" (en) prefix-matches unrelated words
  // and can drag a worse page chunk above the curated fact.
  var STOPWORDS = new RegExp(
    '^(' +
      'a|an|the|is|are|do|does|did|you|your|we|our|i|in|of|to|for|and|or|it|' +
      'what|which|where|when|who|how|many|much|can|could|please|about|tell|me|' +
      'le|la|les|un|une|des|de|du|en|dans|est|sont|vous|nous|votre|vos|que|' +
      'qui|quel|quelle|quels|quelles|o\u00f9|ou|comment|combien|avez|est-ce|' +
      'je|ni|na|ya|wa|za|kwa|gani|ipi|zipi|nini|una|mna|kuna|iko|vipi|' +
      'ngapi|mangapi|wangapi|mingapi|kiasi' +
      ')$',
    'i'
  );

  function stripStopwords(query) {
    var words = query
      .split(/[^\p{L}\p{N}+@.-]+/u)
      .filter(function (w) { return w && !STOPWORDS.test(w); });
    return words.length ? words.join(' ') : query;
  }

  function search(query, l) {
    var entry = getIndex(l);
    if (!entry) return [];
    query = stripStopwords(query);
    var hits = entry.idx.search(query, { limit: 8, suggest: true }) || [];
    if (!hits.length) {
      // Word-by-word fallback: rank docs by how many query words they match.
      var words = query.toLowerCase().split(/[^\p{L}\p{N}+@.-]+/u)
        .filter(function (w) { return w.length >= 3; });
      var counts = {};
      words.forEach(function (w) {
        (entry.idx.search(w, { limit: 8, suggest: true }) || []).forEach(
          function (id, pos) {
            counts[id] = (counts[id] || 0) + 2 - pos / 8;
          }
        );
      });
      hits = Object.keys(counts).sort(function (a, b) {
        return counts[b] - counts[a];
      }).map(Number).slice(0, 8);
    }
    // Curated facts outrank page chunks at similar relevance.
    var ranked = hits.map(function (id, pos) {
      var doc = entry.docs[id];
      return { doc: doc, score: pos - (doc.f ? 2.5 : 0) };
    });
    ranked.sort(function (a, b) { return a.score - b.score; });
    return ranked.map(function (r) { return r.doc; });
  }

  /* ------------------------------------------------------------------ */
  /* Intents  the genuinely useful canned replies kept as first-class   */
  /* ------------------------------------------------------------------ */
  var INTENTS = [
    {
      re: /^\s*(hi|hello|hey|good\s+(morning|afternoon|evening)|bonjour|salut|jambo|hujambo|habari|mambo|shikamoo)\b[\s!.,?]*$/i,
      answer: function () { return { text: t('assistant.greeting') }; },
    },
    {
      re: /\b(thanks?|thank\s+you|merci|asante(\s+sana)?)\b/i,
      answer: function () { return { text: t('assistant.thanks') }; },
    },
    {
      re: /\b(contact|phone|telephone|email|e-?mail|address|reach\s+you|t\u00e9l\u00e9phone|adresse|courriel|contacter|joindre|wasiliana|mawasiliano|simu|barua\s*pepe|anwani)\b/i,
      answer: function () {
        var doc = factById(lang(), 'contact');
        if (!doc) return null; // fall through to search
        return { text: doc.s, links: [{ u: doc.u, t: doc.t }] };
      },
    },
  ];

  function respond(query) {
    for (var i = 0; i < INTENTS.length; i++) {
      if (INTENTS[i].re.test(query)) {
        var ans = INTENTS[i].answer();
        if (ans) return ans;
      }
    }
    var docs = search(query, lang());
    if (!docs.length) {
      var contactLabel =
        (window.LakeI18n && window.LakeI18n.t('footer.contact')) || 'Contact';
      return {
        text: t('assistant.nomatch'),
        links: [{ u: 'contact.html', t: contactLabel }],
        nomatch: true,
      };
    }
    var top = docs[0];
    var links = [{ u: top.u, t: top.t }];
    // Offer one alternate source when the runner-up covers a different page.
    for (var j = 1; j < docs.length && links.length < 2; j++) {
      if (docs[j].u !== top.u) links.push({ u: docs[j].u, t: docs[j].t });
    }
    return { lead: t('assistant.found'), text: top.s, links: links };
  }

  /* ------------------------------------------------------------------ */
  /* UI                                                                  */
  /* ------------------------------------------------------------------ */
  var refs = {};

  function buildUI(mount) {
    mount.innerHTML = '';
    mount.classList.add('la-widget');

    var panel = document.createElement('div');
    panel.className = 'la-panel';
    panel.id = 'la-panel';
    panel.setAttribute('role', 'dialog');
    panel.setAttribute('aria-label', t('assistant.title'));
    panel.hidden = true;

    var head = document.createElement('div');
    head.className = 'la-head';
    head.innerHTML =
      '<span class="la-tick" aria-hidden="true"></span>' +
      '<div class="la-head-txt">' +
      '<h4 data-i18n="assistant.title"></h4>' +
      '</div>';

    var actions = document.createElement('div');
    actions.className = 'la-head-actions';

    var clearBtn = document.createElement('button');
    clearBtn.type = 'button';
    clearBtn.className = 'la-iconbtn la-clear';
    clearBtn.setAttribute('data-i18n-aria', 'assistant.clear');
    clearBtn.setAttribute('data-i18n-title', 'assistant.clear');
    clearBtn.innerHTML =
      '<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M3 6h18M8 6V4h8v2m-9 0 1 14h8l1-14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>';

    var closeBtn = document.createElement('button');
    closeBtn.type = 'button';
    closeBtn.className = 'la-iconbtn la-close';
    closeBtn.setAttribute('data-i18n-aria', 'assistant.close');
    closeBtn.setAttribute('data-i18n-title', 'assistant.close');
    closeBtn.innerHTML =
      '<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M6 6l12 12M18 6L6 18" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>';

    actions.appendChild(clearBtn);
    actions.appendChild(closeBtn);
    head.appendChild(actions);

    var msgs = document.createElement('div');
    msgs.className = 'la-msgs';
    msgs.setAttribute('role', 'log');
    msgs.setAttribute('aria-live', 'polite');

    var form = document.createElement('form');
    form.className = 'la-inputrow';
    var input = document.createElement('input');
    input.type = 'text';
    input.className = 'la-input';
    input.autocomplete = 'off';
    input.maxLength = 300;
    input.setAttribute('data-i18n-placeholder', 'assistant.placeholder');
    input.setAttribute('data-i18n-aria', 'assistant.placeholder');
    var send = document.createElement('button');
    send.type = 'submit';
    send.className = 'la-send';
    send.setAttribute('data-i18n', 'assistant.send');
    form.appendChild(input);
    form.appendChild(send);

    panel.appendChild(head);
    panel.appendChild(msgs);
    panel.appendChild(form);

    var launcher = document.createElement('button');
    launcher.type = 'button';
    launcher.className = 'la-launcher';
    launcher.setAttribute('aria-expanded', 'false');
    launcher.setAttribute('aria-controls', 'la-panel');
    launcher.setAttribute('data-i18n-aria', 'assistant.open');
    launcher.setAttribute('aria-label', t('assistant.open'));
    /* Clean FAB: yellow bubble + navy dots + right-side tail (faces left).
       Fills the launcher (currentColor = brand yellow from assistant.css). */
    launcher.innerHTML =
      '<svg class="la-fab-icon" viewBox="0 0 64 64" aria-hidden="true" focusable="false">' +
      '<path class="la-fab-body" fill="currentColor" d="M44 8h-24c-8.8 0-16 7.2-16 16v10c0 8.8 7.2 16 16 16H36L49.5 59.8c.5.5 1.4.1 1.4-.6V50H44c8.8 0 16-7.2 16-16V24c0-8.8-7.2-16-16-16z"/>' +
      '<ellipse class="la-fab-sheen" cx="32" cy="18" rx="16" ry="5.5" fill="#ffffff" opacity="0.28"/>' +
      '<circle class="la-fab-dot" cx="23.5" cy="27" r="3.15" fill="#0181BB"/>' +
      '<circle class="la-fab-dot" cx="32" cy="27" r="3.15" fill="#0181BB"/>' +
      '<circle class="la-fab-dot" cx="40.5" cy="27" r="3.15" fill="#0181BB"/>' +
      '</svg>';

    mount.appendChild(panel);
    mount.appendChild(launcher);

    refs = {
      mount: mount,
      panel: panel,
      msgs: msgs,
      form: form,
      input: input,
      launcher: launcher,
      clearBtn: clearBtn,
      closeBtn: closeBtn,
    };
    translateUI();
  }

  // Applies assistant.* strings to the widget's own nodes. LakeI18n.applyAll
  // also covers them on every language switch (they carry data-i18n-*), but
  // this handles first paint and pages without the i18n stack.
  function translateUI() {
    refs.panel.setAttribute('aria-label', t('assistant.title'));
    refs.panel.querySelector('h4').textContent = t('assistant.title');
    refs.input.placeholder = t('assistant.placeholder');
    refs.input.setAttribute('aria-label', t('assistant.placeholder'));
    refs.form.querySelector('.la-send').textContent = t('assistant.send');
    refs.launcher.setAttribute('aria-label', t('assistant.open'));
    refs.clearBtn.setAttribute('aria-label', t('assistant.clear'));
    refs.clearBtn.setAttribute('title', t('assistant.clear'));
    refs.closeBtn.setAttribute('aria-label', t('assistant.close'));
    refs.closeBtn.setAttribute('title', t('assistant.close'));
  }

  function renderMessage(msg) {
    var el = document.createElement('div');
    el.className = 'la-msg ' + (msg.role === 'user' ? 'la-user' : 'la-bot');
    if (msg.lead) {
      var lead = document.createElement('span');
      lead.className = 'la-lead';
      lead.textContent = msg.lead;
      el.appendChild(lead);
    }
    var p = document.createElement('p');
    p.textContent = msg.text;
    el.appendChild(p);
    if (msg.links && msg.links.length) {
      var row = document.createElement('span');
      row.className = 'la-links';
      msg.links.forEach(function (link) {
        var a = document.createElement('a');
        a.className = 'la-link';
        a.href = link.u;
        a.textContent = t('assistant.readmore') + ' ' + link.t;
        row.appendChild(a);
      });
      el.appendChild(row);
    }
    refs.msgs.appendChild(el);
    refs.msgs.scrollTop = refs.msgs.scrollHeight;
  }

  function pushMessage(msg, save) {
    renderMessage(msg);
    if (save !== false) {
      storage.add({
        role: msg.role,
        lead: msg.lead || null,
        text: msg.text,
        links: msg.links || null,
        lang: lang(),
        ts: Date.now(),
      });
    }
  }

  function showGreetingIfEmpty() {
    if (!refs.msgs.childElementCount) {
      renderMessage({ role: 'bot', text: t('assistant.greeting') });
    }
  }

  /* Typing indicator ---------------------------------------------------- */
  function withTyping(fn) {
    var typing = document.createElement('div');
    typing.className = 'la-msg la-bot la-typing';
    typing.setAttribute('aria-hidden', 'true');
    typing.innerHTML = '<span></span><span></span><span></span>';
    refs.msgs.appendChild(typing);
    refs.msgs.scrollTop = refs.msgs.scrollHeight;
    setTimeout(function () {
      typing.remove();
      fn();
    }, TYPING_DELAY);
  }

  /* Open / close with focus management ----------------------------------- */
  var lastFocus = null;

  function focusables() {
    return Array.prototype.filter.call(
      refs.panel.querySelectorAll('button, a[href], input'),
      function (el) { return !el.disabled && el.offsetParent !== null; }
    );
  }

  function onPanelKeydown(e) {
    if (e.key !== 'Tab') return;
    var items = focusables();
    if (!items.length) return;
    var first = items[0];
    var last = items[items.length - 1];
    if (e.shiftKey && document.activeElement === first) {
      e.preventDefault();
      last.focus();
    } else if (!e.shiftKey && document.activeElement === last) {
      e.preventDefault();
      first.focus();
    }
  }

  function isPanelOpen() {
    return refs.panel && !refs.panel.hidden;
  }

  function onDocumentKeydown(e) {
    if (e.key !== 'Escape' || !isPanelOpen()) return;
    e.preventDefault();
    closePanel();
  }

  function onDocumentPointerDown(e) {
    if (!isPanelOpen()) return;
    var t = e.target;
    /* Ignore clicks inside the open panel or on the FAB (FAB still toggles via its own handler). */
    if (refs.panel.contains(t) || refs.launcher.contains(t)) return;
    closePanel();
  }

  function openPanel() {
    lastFocus = document.activeElement;
    refs.panel.hidden = false;
    // Two rAFs so the transition runs from the un-opened state.
    requestAnimationFrame(function () {
      requestAnimationFrame(function () {
        refs.panel.classList.add('la-open');
      });
    });
    refs.launcher.setAttribute('aria-expanded', 'true');
    refs.mount.classList.add('la-panel-open');
    showGreetingIfEmpty();
    refs.panel.addEventListener('keydown', onPanelKeydown);
    document.addEventListener('keydown', onDocumentKeydown);
    document.addEventListener('pointerdown', onDocumentPointerDown, true);
    refs.input.focus();
  }

  function closePanel() {
    refs.panel.classList.remove('la-open');
    refs.panel.hidden = true;
    refs.launcher.setAttribute('aria-expanded', 'false');
    refs.mount.classList.remove('la-panel-open');
    refs.panel.removeEventListener('keydown', onPanelKeydown);
    document.removeEventListener('keydown', onDocumentKeydown);
    document.removeEventListener('pointerdown', onDocumentPointerDown, true);
    if (lastFocus && lastFocus.focus) lastFocus.focus();
    else refs.launcher.focus();
  }

  function togglePanel() {
    if (refs.panel.hidden) openPanel();
    else closePanel();
  }

  /* ------------------------------------------------------------------ */
  /* Boot                                                                */
  /* ------------------------------------------------------------------ */
  function init() {
    var mount = document.getElementById('chat-widget');
    if (!mount) {
      mount = document.createElement('div');
      mount.id = 'chat-widget';
      document.body.appendChild(mount);
    }
    buildUI(mount);

    refs.launcher.addEventListener('click', togglePanel);
    refs.closeBtn.addEventListener('click', closePanel);

    refs.clearBtn.addEventListener('click', function () {
      storage.clear().then(function () {
        refs.msgs.innerHTML = '';
        renderMessage({ role: 'bot', text: t('assistant.cleared') });
        refs.input.focus();
      });
    });

    refs.form.addEventListener('submit', function (e) {
      e.preventDefault();
      var text = refs.input.value.trim();
      if (!text) return;
      refs.input.value = '';
      pushMessage({ role: 'user', text: text });
      withTyping(function () {
        var ans = respond(text);
        pushMessage({
          role: 'bot',
          lead: ans.lead,
          text: ans.text,
          links: ans.links,
        });
      });
    });

    // Restore history (per browser) from IndexedDB.
    storage.load().then(function (messages) {
      messages.forEach(function (m) {
        renderMessage({
          role: m.role,
          lead: m.lead,
          text: m.text,
          links: m.links,
        });
      });
    });

    // Live language switching: LakeI18n.applyAll translates the data-i18n
    // nodes; this covers attributes + first-class strings.
    document.addEventListener('lake-i18n-applied', translateUI);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
